chart.options:
chart: {
  type: 'bar',
  height: 430
},
plotOptions: {
  bar: {
    horizontal: true,
    dataLabels: {
      position: 'top',
    },
  }
},
dataLabels: {
  enabled: false
},
stroke: {
  show: true,
  width: 1,
  colors: ['#fff']
},
grid: {
  padding: {
    right: 30
  }
},
tooltip: {
  shared: true,
  intersect: false
},
title: {
  text: 'Marketing Spend vs Revenue by Channel',
  align: 'left'
},
xaxis: {
  categories: ['Email', 'Social', 'Search', 'Display', 'Affiliate', 'Referral', 'Direct'],
  labels: {
    formatter: function (val) {
      return '$' + Math.round(val) + 'k'
    }
  }
},
